import { MakeLogicType, actions, connect, kea, key, listeners, path, props, reducers, selectors } from 'kea'

import { teamLogic } from 'scenes/teamLogic'

import type { ProductKey } from '~/queries/schema/schema-general'

import type { ProductEmptyStateMode, ProductSetupStatus } from './types'

export interface ProductSetupStatusLogicProps {
    productKey: ProductKey
}

interface DetectedStatus {
    status: ProductSetupStatus
    teamId: number | null
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface productSetupStatusLogicValues {
    currentTeamId: number | null // teamLogic
    detected: DetectedStatus
    mode: ProductEmptyStateMode
    showEmptyState: boolean
    skipped: boolean
    skippedByTeam: Record<number, boolean>
    status: ProductSetupStatus
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface productSetupStatusLogicActions {
    applyDetectedStatus: (
        status: ProductSetupStatus,
        teamId: number | null
    ) => {
        status: ProductSetupStatus
        teamId: number | null
    }
    setDetectedStatus: (status: ProductSetupStatus) => {
        status: ProductSetupStatus
    }
    setSkippedForTeam: (
        teamId: number,
        skipped: boolean
    ) => {
        skipped: boolean
        teamId: number
    }
    skipEmptyState: () => {
        value: true
    }
    unskipEmptyState: () => {
        value: true
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface productSetupStatusLogicMeta {
    key: ProductKey
    __keaTypeGenInternalSelectorTypes: {
        status: (detected: DetectedStatus, currentTeamId: number | null) => ProductSetupStatus
        skipped: (skippedByTeam: Record<number, boolean>, currentTeamId: number | null) => boolean
        showEmptyState: (status: ProductSetupStatus, skipped: boolean) => boolean
        mode: (status: ProductSetupStatus) => ProductEmptyStateMode
    }
}

export type productSetupStatusLogicType = MakeLogicType<
    productSetupStatusLogicValues,
    productSetupStatusLogicActions,
    ProductSetupStatusLogicProps,
    productSetupStatusLogicMeta
>

/**
 * The single read point for "is product X set up?".
 *
 * Detection stays with each product (they know their own events/APIs), but every
 * product pushes its normalized `ProductSetupStatus` here via `setDetectedStatus`,
 * so any surface — the scene-level empty-state gate, nav, activation — can ask one
 * place instead of reaching into per-product logics.
 *
 * Detection must be a real signal: data existence (HogQL count / exists API), the
 * product's opt-in flag, or entity count for creation-first products. Never a
 * dismissal flag — `has_completed_onboarding_for` is routing metadata, not evidence
 * of data.
 *
 * Skip is local-only (per browser, keyed by team): it bypasses the empty-state
 * screen without writing anything to the backend, and detection keeps running so
 * the real product appears as soon as data lands.
 */
export const productSetupStatusLogic = kea<productSetupStatusLogicType>([
    props({} as ProductSetupStatusLogicProps),
    key((props) => {
        if (!props.productKey) {
            throw new Error('productSetupStatusLogic must be initialized with a productKey')
        }
        return props.productKey
    }),
    path((key) => ['lib', 'components', 'ProductEmptyState', 'productSetupStatusLogic', key]),
    connect(() => ({ values: [teamLogic, ['currentTeamId']] })),
    actions({
        setDetectedStatus: (status: ProductSetupStatus) => ({ status }),
        applyDetectedStatus: (status: ProductSetupStatus, teamId: number | null) => ({ status, teamId }),
        skipEmptyState: true,
        unskipEmptyState: true,
        setSkippedForTeam: (teamId: number, skipped: boolean) => ({ teamId, skipped }),
    }),
    reducers({
        // Stamped with the team the detection ran against, so a stale answer is
        // never served across a project switch (see the `status` selector).
        detected: [
            { status: 'loading', teamId: null } as DetectedStatus,
            {
                applyDetectedStatus: (_, { status, teamId }) => ({ status, teamId }),
            },
        ],
        // Keyed by team so switching projects never leaks a skip across tenants.
        skippedByTeam: [
            {} as Record<number, boolean>,
            { persist: true },
            {
                setSkippedForTeam: (state, { teamId, skipped }) => ({ ...state, [teamId]: skipped }),
            },
        ],
    }),
    selectors({
        // A detected status only counts for the team it was detected for; after a
        // project switch we're back to `loading` until a detection (or the preload)
        // answers for the new team.
        status: [
            (s) => [s.detected, s.currentTeamId],
            (detected: DetectedStatus, currentTeamId: number | null): ProductSetupStatus =>
                detected.teamId === currentTeamId ? detected.status : 'loading',
        ],
        skipped: [
            (s) => [s.skippedByTeam, s.currentTeamId],
            (skippedByTeam: Record<number, boolean>, currentTeamId: number | null): boolean =>
                !!(currentTeamId && skippedByTeam[currentTeamId]),
        ],
        showEmptyState: [
            (s) => [s.status, s.skipped],
            (status: ProductSetupStatus, skipped: boolean): boolean =>
                !skipped && (status === 'needs-setup' || status === 'waiting-for-data'),
        ],
        mode: [
            (s) => [s.status],
            (status: ProductSetupStatus): ProductEmptyStateMode =>
                status === 'waiting-for-data' ? 'waiting-for-data' : 'needs-setup',
        ],
    }),
    listeners(({ actions, values }) => ({
        setDetectedStatus: ({ status }) => {
            actions.applyDetectedStatus(status, values.currentTeamId)
        },
        skipEmptyState: () => {
            if (values.currentTeamId) {
                actions.setSkippedForTeam(values.currentTeamId, true)
            }
        },
        unskipEmptyState: () => {
            if (values.currentTeamId) {
                actions.setSkippedForTeam(values.currentTeamId, false)
            }
        },
    })),
])
